import React, { useState, useEffect } from 'react';
import axios from 'axios';
import { useLocation } from 'react-router-dom';
import './AppointmentForm.css';

const AppointmentForm = () => {
  const location = useLocation();
  const [doctors, setDoctors] = useState([]);
  const [selectedDoctor, setSelectedDoctor] = useState(null);
  const [availableSlots, setAvailableSlots] = useState([]);

  const [formData, setFormData] = useState({
    patientName: '',
    email: '',
    phone: '',
    age: '',
    gender: '',
    doctor: '',
    appointmentDate: '',
    appointmentTime: '',
    reason: '',
    symptoms: '',
    previousMedicalHistory: ''
  });

  useEffect(() => {
    // Fetch doctors
    const fetchDoctors = async () => {
      try {
        const response = await axios.get('http://localhost:5000/api/doctors');
        setDoctors(response.data);

        // If doctor ID is in URL params, select that doctor
        const params = new URLSearchParams(location.search);
        const doctorId = params.get('doctor');
        if (doctorId) {
          const doctor = response.data.find(d => d._id === doctorId);
          if (doctor) {
            setSelectedDoctor(doctor);
            setFormData(prev => ({ ...prev, doctor: doctor._id }));
          }
        }
      } catch (error) {
        console.error('Error fetching doctors:', error);
      }
    };
    fetchDoctors();
  }, [location]);

  useEffect(() => {
    // Fetch available slots when doctor and date are selected
    const fetchAvailableSlots = async () => {
      if (formData.doctor && formData.appointmentDate) {
        try {
          const response = await axios.get(
            `http://localhost:5000/api/doctors/${formData.doctor}/available-slots/${formData.appointmentDate}`
          );
          setAvailableSlots(response.data.availableSlots);
        } catch (error) {
          console.error('Error fetching slots:', error);
        }
      }
    };
    fetchAvailableSlots();
  }, [formData.doctor, formData.appointmentDate]);

  const handleChange = (e) => {
    const { name, value } = e.target;
    setFormData(prev => ({
      ...prev,
      [name]: value
    }));

    if (name === 'doctor') {
      const doctor = doctors.find(d => d._id === value);
      setSelectedDoctor(doctor);
    }
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    try {
      const response = await axios.post('http://localhost:5000/api/appointments', formData);
      alert('Appointment booked successfully!');
      setFormData({
        patientName: '',
        email: '',
        phone: '',
        age: '',
        gender: '',
        doctor: selectedDoctor ? selectedDoctor._id : '',
        appointmentDate: '',
        appointmentTime: '',
        reason: '',
        symptoms: '',
        previousMedicalHistory: ''
      });
    } catch (error) {
      alert('Error booking appointment. Please try again.');
      console.error('Error:', error);
    }
  };

  return (
    <div className="appointment-form">
      <h2>Book an Appointment</h2>
      <form onSubmit={handleSubmit}>
        <div className="form-group">
          <label>Patient Name:</label>
          <input
            type="text"
            name="patientName"
            value={formData.patientName}
            onChange={handleChange}
            required
          />
        </div>

        <div className="form-group">
          <label>Email:</label>
          <input
            type="email"
            name="email"
            value={formData.email}
            onChange={handleChange}
            required
          />
        </div>

        <div className="form-group">
          <label>Phone:</label>
          <input
            type="tel"
            name="phone"
            value={formData.phone}
            onChange={handleChange}
            required
          />
        </div>

        <div className="form-group">
          <label>Age:</label>
          <input
            type="number"
            name="age"
            value={formData.age}
            onChange={handleChange}
            required
          />
        </div>

        <div className="form-group">
          <label>Gender:</label>
          <select
            name="gender"
            value={formData.gender}
            onChange={handleChange}
            required
          >
            <option value="">Select Gender</option>
            <option value="Male">Male</option>
            <option value="Female">Female</option>
            <option value="Other">Other</option>
          </select>
        </div>

        <div className="form-group">
          <label>Select Doctor:</label>
          <select
            name="doctor"
            value={formData.doctor}
            onChange={handleChange}
            required
          >
            <option value="">Select Doctor</option>
            {doctors.map(doctor => (
              <option key={doctor._id} value={doctor._id}>
                Dr. {doctor.name} - {doctor.specialization}
              </option>
            ))}
          </select>
        </div>

        {selectedDoctor && (
          <div className="doctor-details">
            <p>Consultation Fee: ${selectedDoctor.consultationFee}</p>
            <p>Available Days: {selectedDoctor.availableDays.join(', ')}</p>
          </div>
        )}

        <div className="form-group">
          <label>Appointment Date:</label>
          <input
            type="date"
            name="appointmentDate"
            value={formData.appointmentDate}
            onChange={handleChange}
            required
          />
        </div>

        <div className="form-group">
          <label>Appointment Time:</label>
          <select
            name="appointmentTime"
            value={formData.appointmentTime}
            onChange={handleChange}
            required
          >
            <option value="">Select Time</option>
            {availableSlots.map((slot, index) => (
              <option key={index} value={slot.startTime}>
                {slot.startTime} - {slot.endTime}
              </option>
            ))}
          </select>
        </div>

        <div className="form-group">
          <label>Reason for Visit:</label>
          <textarea
            name="reason"
            value={formData.reason}
            onChange={handleChange}
            required
          ></textarea>
        </div>

        <div className="form-group">
          <label>Symptoms:</label>
          <textarea
            name="symptoms"
            value={formData.symptoms}
            onChange={handleChange}
            required
          ></textarea>
        </div>

        <div className="form-group">
          <label>Previous Medical History:</label>
          <textarea
            name="previousMedicalHistory"
            value={formData.previousMedicalHistory}
            onChange={handleChange}
          ></textarea>
        </div>

        <button type="submit">Book Appointment</button>
      </form>
    </div>
  );
};

export default AppointmentForm;
